<template>
  <v-container fluid class="pa-6 pt-4 fill-height safety-monitoring-history white">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="82" class="pa-0">
        <i-card-top
          class="d-md-flex"
          :useBtnList="buttonUseList"
          @btnSearch="btnSearch(true)"
        >
          <template #body>
            <v-layout column>
              <v-row no-gutters align="center" class="pa-0 pt-2">
                <v-col cols="12" md="2" class="pr-2">
                  <v-select
                    v-model="search.cctv_id"
                    :items="CCTVList"
                    item-text="cctv_id"
                    item-value="cctv_id"
                    :menu-props="{ offsetY: true, class: 'safety-select' }"
                    multiple
                    dense
                    outlined
                    clearable
                    :placeholder="$t('cctvList')"
                    color="primary"
                    class="mx-1 safety-select"
                  >
                    <template #selection="{ item, index }">
                      <span v-if="index === 0">{{ item.cctv_name }}</span>
                      <span
                        v-if="index === 1"
                        class="ml-1 grey--text text-caption"
                      >
                        {{ `(+${selectedCCTVList.length - 1} 개)` }}
                      </span>
                    </template>
                  </v-select>
                </v-col>
                <v-col cols="12" md="3" class="pr-2">
                  <v-select
                    v-model="search.event_type"
                    :items="eventList"
                    item-text="eventDesc"
                    item-value="eventType"
                    :menu-props="{ offsetY: true, class: 'safety-select' }"
                    multiple
                    dense
                    outlined
                    clearable
                    :placeholder="$t('eventList')"
                    color="primary"
                    class="mx-1 safety-select"
                  >
                    <template #selection="{ item, index }">
                      <span v-if="index === 0">{{ item.eventDesc }}</span>
                      <span
                        v-if="index === 1"
                        class="ml-1 grey--text text-caption"
                      >
                        {{ `(+${selectedEventList.length - 1} 개)` }}
                      </span>
                    </template>
                  </v-select>
                </v-col>
                <v-col cols="2">
                  <i-date-time-picker
                    :firstDisplayDate="search.start_date"
                    :dateOnly="true"
                    label="계획시작일자"
                    class="mx-1"
                    :allowMaxDate="search.end_date"
                    @getDate="setSearchDate($event, 'start')"
                  >
                  </i-date-time-picker>
                </v-col>
                <span class="pt-1 mx-1">
                  ~
                </span>
                <v-col cols="2">
                  <i-date-time-picker
                    :firstDisplayDate="search.end_date"
                    :dateOnly="true"
                    label="계획종료일자"
                    class="mx-1"
                    :allowMinDate="search.start_date"
                    :allowMaxDate="currentDate"
                    @getDate="setSearchDate($event, 'end')"
                  >
                  </i-date-time-picker>
                </v-col>
                <!-- <v-col cols="12" md="4">
                  <v-text-field
                    v-model="docName"
                    :placeholder="$t('docName')"
                    class="mx-1 py-2 py-md-0"
                    dense
                    outlined
                    hide-details="auto"
                    @keydown.enter="btnSearch()"
                    clearable
                  />
                </v-col> -->
              </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-sheet>
      <v-col class="pa-0">
        <i-card-vertical :headerTitle="`${$t('safetyMonitoringHistory')}`" device="web">
          <template #body>
            <v-layout overflow-auto>
              <v-col cols="12" class="pa-0">
                <DxDataGrid
                  :key="gridKey"
                  id="safetyMonitoringHistorys"
                  class="safety-monitoring-history-layout-col-height"
                  :ref="dxDataGridRef"
                  :data-source="dataSource"
                  width="100%"
                  :remote-operations="false"
                  :show-borders="true"
                  :show-row-lines="true"
                  :column-auto-width="true"
                  :allow-column-resizing="true"
                  :allow-column-reordering="true"
                  :repaint-changes-only="false"
                  :focused-row-enabled="true"
                  key-expr="index"
                  @editing-start="onEditingStart"
                  @editor-preparing="
                      e => {
                        onEditorPreparing(e)
                      }
                    "
                  @focused-row-changed="handleFocusedRow"
                >
                  
                  <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />
                  <DxScrolling row-rendering-mode="standard" />
                  <DxSelection select-all-mode="allPages" show-check-boxes-mode="always" mode="single" />

                  <DxColumn data-field="event_type_name" data-type="string" :caption="$t('eventType')" :width="150" alignment="center" :visible="true" :allow-editing="false" />
                  <!-- <DxColumn data-field="group_name" data-type="string" :caption="$t('group')" :width="150" alignment="center" :visible="true" :allow-editing="false" /> -->
                  <DxColumn data-field="cctv_id" data-type="string" :caption="$t('cctvNm')" :width="150" alignment="center" :visible="true" :allow-editing="false" />
                  <DxColumn data-field="event_time" data-type="datetime" :caption="$t('occurrenceAt')" :width="200" alignment="center" :visible="true" :allow-editing="false" />
                  <DxColumn data-field="event_desc" data-type="string" :caption="$t('eventType')" :width="150" alignment="left" :visible="true" :allow-editing="false" />
                  <!-- <DxColumn data-field="remark" data-type="string" :caption="$t('contents')" alignment="center" :visible="true" :allow-editing="false" /> -->
                </DxDataGrid>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
      <v-sheet width="600" height="calc(100vh - 248px)" class="pl-4 pr-2">
        <v-sheet width="100%" height="32">
          <h6 class="text-lg-h6 font-weight-bold">{{ $t('detailInfo') }}</h6>
        </v-sheet>
        <template v-if="selectedRow.file_path">
          <v-sheet height="40" class="pl-4 pr-0 grey--text d-flex align-center">
            <span class="text-body-1 font-weight-bold">{{ selectedRow.event_type_name }}</span>
            <v-spacer />
            <span class="text-body-1 font-weight-bold">{{ selectedRow.cctv_id }}</span>
            <v-divider vertical class="mx-2" />
            <span class="text-body-1 font-weight-bold">{{ selectedRow.event_time }}</span>
          </v-sheet>
          <v-sheet height="40" class="pl-4 pr-0 grey--text d-flex align-center justify-end">
            <span class="text-body-1 font-weight-bold">{{ selectedRow.event_desc || '-' }}</span>
          </v-sheet>
          <v-sheet height="calc(100% - 80px - 32px - 60px)" style="position: relative;" class="d-flex align-start justify-center">
            <template v-if="selectedRow.event_type  == 'E003'">
              <video v-if="videoUrl" ref="videoPlayer" controls autoplay width="100%" style="aspect-ratio: 1.15/1; height: inherit;">
                <source :src="videoUrl" type="video/mp4" />
              </video>
              <span v-if="!videoUrl">영상을 불러오고 있습니다.</span>
            </template>
            <template v-else>
              <v-sheet  height="100%" style="overflow-x: auto;">
                <v-img  class="scrollable-image" v-if="image.url" height="100%" :style="`aspect-ratio: ${image.ratio};`" :src="image.url" />
              </v-sheet>
            </template>
          </v-sheet>
          <v-sheet height="48" class="mt-3 d-flex align-end">
            <v-text-field
              v-model="selectedRow.remark"
              outlined
              hide-details
              height="40"
              @keyup.enter="saveRemark"
            />
            <v-btn small text outlined height="40" width="80" class="ml-3" color="primary" @click="saveRemark">
              {{ $t('btnSave') }}
            </v-btn>
        </v-sheet>
      </template>
      </v-sheet>
    </v-row>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue'
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import iDateTimePicker from '@/components/common/iDateTimePicker.vue'

import { getCCTVList } from '@/api/realTimeVideoSafetyManagement/safetyDetectionCameraManage.js'
import { getPreMonth, getDateCustomFormat } from '@/utils/common.js'
import { getEventHistoryList, setEventRemark, setEventReadAlert, getEventFiles, getCctvServerInfo } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringHistory.js'

import { getUserCd } from '@/utils/token'
export default {
  mixins: [baseview, BaseDataGrid],
  name: 'SafetyMonitoringHistory',
  components: {
    'i-card-top': iCardTop,
    'i-date-time-picker': iDateTimePicker,
    'i-card-vertical': iCardVertical
  },
  computed: {
    dataGridMain() {
      return this.$refs[this.dxDataGridRef].instance
    },
  },
  data() {
    return {
      videoUrl: '',
      buttonUseList: [
        'btnSearch', //조회
      ],
      selectedCCTVList: [],
      search: {
        cctv_id: [],
        event_type: [],
        start_date: getPreMonth(1),
        end_date: getPreMonth(0),
        userCd: getUserCd()
      },
      CCTVList: [],
      selectedEventList: [],
      eventList: [
        { eventType: 'E001', eventDesc: '안전장비 미착용' },
        { eventType: 'E002', eventDesc: '위험구역 출입' },
        { eventType: 'E003', eventDesc: '쓰러짐' },
        { eventType: 'E004', eventDesc: '위험체 충돌 위험' },
        // { eventType: 'E004', eventDesc: '기계 및 차량 접근 경고' },
      ],
      image: {
        ratio: 16/9,
        url: null
      },
      currentDate: getPreMonth(0),
      gridKey: 0,
      dxDataGridRef: 'safetyMonitoringHistory',
      selectedRow: {},
      dataSource: []
    }
  },
  methods: {
    handleCreated() {
      getCCTVList()
        .then(res => {
          this.CCTVList = res.list
        })
      // if(this.dataSource.length !== 0) {
      //   const firstRow = this.dataSource[0]
      //   console.log('text', firstRow?.event_time)
      //   this.$nextTick(() => {
      //     // this.dataGridMain.selectRows(firstRow.event_time, true)
      //   })
      // }
    },
    setSearchDate(e, param) {
      if(param == 'start'){
        this.search.start_date = e
      } else {
        this.search.end_date = e
      }
    },
    btnSearch(isForce) {
      const dateFormat = 'YYYY.MM.DD'
      const param = {
        cctv_id: this.search.cctv_id,
        event_type: this.search.event_type,
        start_date: getDateCustomFormat(this.search.start_date, dateFormat),
        end_date: getDateCustomFormat(this.search.end_date, dateFormat),
        userCd: this.search.userCd
      }
      getEventHistoryList(param, !isForce)
        .then(res => {
          this.image.url = null
          this.selectedRow = {}
          this.dataSource = res.list.map((el, index) => {
            return {
              ...el,
              index,
              event_type_name: this.eventList.find(fel => fel.eventType == el.event_type)?.eventDesc
            }
          })
          if(isForce) {
            this.$nextTick(() => {
              this.dataGridMain.cancelEditData()
              this.dataGridMain.collapseAdaptiveDetailRow()
              this.dataGridMain.refresh()
              this.dataGridMain.clearSelection()
              this.dataGridMain.option('focusedRowIndex', 0)
              if(this.dataSource.length !== 0) {
                this.handleFocusedRow({ row: { data: this.dataSource[0] } })
              }
            })
          }
        })
    },
    onEditingStart(e) {

    },
    handleFocusedRow(e) {
      const rowData = e.row.data
      this.selectedRow = rowData
      const param = {
        cctv_id: rowData.cctv_id,
        file_path: rowData.file_path
      }
      
      if (rowData.event_type != 'E003') {
        getEventFiles(param)
        .then(async res => {
          if(res.success) {
            if(res.ratio) {
              let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
              this.image.ratio = x/y
            }
            const byteCharacters = atob(res.img_decode_data)
            const byteNumbers = new Array(byteCharacters.length).fill().map((_, i) => byteCharacters.charCodeAt(i))
            const byteArray = new Uint8Array(byteNumbers)
            const blobType = rowData.event_type == 'E003' ? 'video/mp4' : 'image/jpeg'
            const blob = new Blob([byteArray], { type: blobType })
            this.image.url = URL.createObjectURL(blob)
          } else {
            this.image.url = null
          }
        })
      } else {
        // Flask 서버에 파일 경로 전달
        let param1 = rowData.cctv_id
        getCctvServerInfo(param1).then(async res=> {
          // console.log(res)
          if(res.cctv_id === rowData.cctv_id) {
            this.videoUrl = `http://${res.server_host}:${res.api_port}/cctv/process/video?path=${encodeURIComponent(rowData.file_path)}`;
            this.$nextTick(() => {
              this.$refs.videoPlayer.load(); // 비디오 다시 로드
            });
          }
        })
        
      }
       
      
    },
    async saveRemark() {
      if (!this.selectedRow) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        current => {
          const param = {
            cctv_id: this.selectedRow.cctv_id,
            event_time: this.selectedRow.event_time,
            remark: this.selectedRow.remark
          }
          setEventRemark(param, true)
            .then(res => {

            })
            
        },
        null,
        true
      )
      // const find = this.dataSource.find(el => el.id == this.selectedRow.id)
      // if(find) {
      //   this.dataGridMain.saveEditData()
      //   this.openLoading('saving')
      //   // setEventRemark
      //   this.dataGridMain.beginUpdate()
      //   find.remark = this.selectedRow.remark
      //   this.dataGridMain.endUpdate()
      //   this.endLoading()

      //   console.log(this.dataSource)
      // }
      
    },
  },
  created() {
    this.handleCreated()
  },
  mounted() {
    this.$nextTick(() => {
      this.btnSearch(true)
    })
  },
  destroy() {
  },
  // beforeRouteLeave(to, from, next) {
  //   window.removeEventListener('keydown', this.handleKeydown)
  //   next()
  // }
}
</script>

<style lang="scss">
.safety-monitoring-history {
  $secondary: #3F51B5;
  $secondary-opacity: #3f51b544;
  $appBarHeight: 65px;
  $cardTitleHeight: 62px;
  $conditionOneHeight: 46px;
  $paddingHeight: 8px;
  $spare: 3.5vh;
  > div {
    position: relative;
    .v-divider {
      border-width: 0.1rem;
      height: 16px !important;
      min-height: 16px !important;
      align-self: center;
    }
    tr.dx-data-row {
      cursor: pointer;
    }
  }
  &-layout-col-height {
    min-height: calc(100vh - (#{$appBarHeight} + #{$cardTitleHeight} + #{$conditionOneHeight} + (#{$paddingHeight} * 9.9) + #{$spare})) !important;
  }
  .scrollable-image {
  min-width: 200%; /* 이미지가 부모보다 크도록 설정 */
  height: auto;
  }
}
</style>